 1	import * as React from 'react';
 2	import {
 3	  Dropdown,
 4	  DropdownItem,
 5	  DropdownList,
 6	  MenuToggle,
 7	  MenuToggleElement,
 8	} from '@patternfly/react-core';
 9	import { map } from 'lodash';
10	import { StatusOptions } from './utils';
11	
12	const StatusDropdown = () => {
13	  const [isOpen, setValue] = React.useState(false);
14	  const toggleIsOpen = React.useCallback(() => setValue((v) => !v), []);
15	  const setClosed = React.useCallback(() => setValue(false), []);
16	  const statusOptions = StatusOptions();
17	  return (
18	    <div className="form-group">
19	      <div>
20	        <Dropdown
21	          isOpen={isOpen}
22	          onOpenChange={(isOpen: boolean) => setValue(isOpen)}
23	          toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
24	            <MenuToggle ref={toggleRef} onClick={toggleIsOpen}>
25	              {'All statuses'}
26	            </MenuToggle>
27	          )}
28	        >
29	          <DropdownList>
30	            {map(statusOptions, (name, key) => (
31	              <DropdownItem
32	                component="button"
33	                key={key}
34	                onClick={() => {
35	                  setClosed();
36	                }}
37	              >
38	                {name}
39	              </DropdownItem>
40	            ))}
41	          </DropdownList>
42	        </Dropdown>
43	      </div>
44	    </div>
45	  );
46	};
47	
48	export default StatusDropdown;

